const rawInput = $input.all().map(i => i.json);
const nodes = rawInput.flatMap(item => item.node || []);
const results = [];

for (const node of nodes) {
  const componentName = node.componentName;

  const elementParams = node.elementParameter || [];
  const uniqueNameParam = elementParams.find(p => p.name === "UNIQUE_NAME");
  const checkParam = elementParams.find(p => p.field == "CHECK" && p.name == "ACTIVATE" && p.value == "false")

  const queryParam = elementParams.find(p => p.name === "QUERY" && p.field === "MEMO_SQL");

  if (!queryParam || !queryParam.value || queryParam.value === "\"\"") continue;

  const uniqueName = uniqueNameParam?.value?.replace(/^"|"$/g, '') || null;

  const memoSQL = queryParam.value
    .replace(/^"|"$/g, '')                  // Hapus kutip luar
    .replace(/\\"/g, '"')                   // Unescape
    .replace(/\\r\\n|\\n|\\r/g, '\n')       // Newline asli
    .replace(/\/\*[\s\S]*?\*\//g, '')       // Komentar multi-baris
    .split('\n')
    .filter(line => !line.trim().startsWith('--')) // Komentar satu baris
    .join(' ')
    .replace(/"\s*\+\s*/g, '')              // Hapus bagian seperti '"+ 
    .replace(/\s*\+\s*"/g, '')              // Hapus bagian seperti + "'
    .replace(/\+/g, '')                     // Hapus +
    .replace(/"/g, '')                      // Hapus quote sisa
    .replace(/context\.(\w+)/g, '{{$1}}')   // Ubah context.var → {{var}}
    .replace(/\s+/g, ' ')                   // Normalisasi spasi
    .trim();

  const metadata = node.metadata || [];
  const connectors = (Array.isArray(metadata) ? metadata : [metadata])
    .map(m => m.name)
    .filter(Boolean);

  results.push({
    componentName,
    uniqueName,
    memoSQL,
    connectors,
    checkParam
  });
}

return [{"node " : results}];

