const input = $input.item.json;

// contextParameter sudah berupa objek, langsung gunakan.
// Kita hanya perlu membersihkan nilai-nilainya dari tanda kutip ganda.
const contextVars = {};
if (input.contextParameter) {
    for (const key in input.contextParameter) {
        if (Object.prototype.hasOwnProperty.call(input.contextParameter, key)) {
            let value = input.contextParameter[key];
            // Pastikan nilai adalah string sebelum mencoba replace
            if (typeof value === 'string') {
                contextVars[key] = value.replace(/^"|"$/g, '');
            } else {
                contextVars[key] = value; // Biarkan tipe data lain apa adanya
            }
        }
    }
}

const nodes = input["node "] || []; // perhatikan: ada spasi setelah "node "

const results = [];

function replaceVariables(sql, contextVars) {
  // Regex untuk mencocokkan {{VAR_NAME}}
  return sql.replace(/{{(.*?)}}/g, (_, varName) => {
    let value = contextVars[varName];
    if (value === undefined) {
      return `{{${varName}}}`; // Biarkan variabel tidak terganti jika tidak ditemukan di contextVars
    }
    return value;
  });
}

for (const node of nodes) {
  const componentName = node.componentName;
  const uniqueName = node.uniqueName;
  const memoSQLRaw = node.memoSQL || '';
  const connectors = node.connectors || [];

  const resolvedSQL = replaceVariables(memoSQLRaw, contextVars);

  results.push({
    componentName,
    uniqueName,
    memoSQL_resolved: resolvedSQL,
    connectors
  });
}

return results.map(r => ({ json: r }));

