// Fungsi untuk mapping schema ke kategori
function mapSchemaCategory(tableName, componentName) {
  const schema = tableName.split('.')[0].toUpperCase();

  if (datamart_schema.includes(schema)) return 'DATAMART';
  else if (staging_schema.includes(schema) && componentName != 'tOracleInput') return 'STAGING';
  else if  (source_data.includes(schema) && componentName == 'tOracleInput') return 'SOURCE DATA';
  else if (source_data.includes(schema)) return 'SOURCE DATA';
  else if (others_schema.includes(schema)) return 'OTHERS';
  // else return 'UNKNOW'

  return 'UNKNOWN';
}

