const items = $input.all();
let merged = [];

// Gabungkan dan parse semua array dari properti "output"
for (const item of items) {
  const componentName = item.json.componentName;

  try {
    // Ambil bagian array valid dari output
    const output = item.json.output;

    // Cari array JSON dalam string (gunakan regex untuk ambil bagian dalam [])
    const match = output.match(/\[(.*?)\]/s);
    if (!match) continue;

    const arrayStr = `[${match[1]}]`.replace(/(\r\n|\n|\r)/gm, "").replace(/,\s*]/, "]");
    const parsed = JSON.parse(arrayStr);

    if (Array.isArray(parsed)) {
      for (const table of parsed) {
        merged.push({ source_table_name: table, componentName });
      }
    }
  } catch (err) {
    // Jika gagal parse, skip
    continue;
  }
}

// Hapus duplikat berdasarkan kombinasi table + componentName
const seen = new Set();
const unique = merged.filter(item => {
  const key = `${item.source_table_name}::${item.componentName}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Kembalikan sebagai array of objects
return unique.map(({ source_table_name, componentName }) => ({
  json: { source_table_name, componentName }
}));

